return items
  .filter(item => item.json.prompt && String(item.json.status || '').toLowerCase() !== 'done')
  .map(item => {
    const j = item.json;
    const slug = (v, fb) => String(v || fb).toLowerCase().replace(/[^a-z0-9._-]+/g, '-').replace(/-+/g, '-').replace(/^[._-]+|[._-]+$/g, '').slice(0, 80) || fb;
    const safeFolder = slug(j.subfolder, 'documentary-series');
    const safePrefix = slug(j.filename_prefix, 'clip');
    return { json: {
      row_id: j.row_id,
      prompt: j.prompt,
      negative_prompt: j.negative_prompt || 'low quality, blurry, distorted, watermark, text, logo',
      subfolder: safeFolder,
      filename_prefix: safePrefix,
      seed: j.seed ? Number(j.seed) : undefined,
      num_frames: j.num_frames ? Number(j.num_frames) : 16,
      num_inference_steps: j.steps ? Number(j.steps) : 25,
      guidance_scale: j.guidance_scale ? Number(j.guidance_scale) : 9,
      width: j.width ? Number(j.width) : 256,
      height: j.height ? Number(j.height) : 256,
      fps: j.fps ? Number(j.fps) : 8
    }};
  });

return items.map(item => {
  const r = item.json;
  if (r.status !== 'completed' || !r.video_url) throw new Error('Colab generation failed: ' + JSON.stringify(r));
  const file = String(r.file_name || (r.job_id + '.mp4')).replace(/[^a-zA-Z0-9._-]/g, '_');
  const folder = String($('Prepare Rows').item.json.subfolder || 'documentary-series').replace(/[^a-zA-Z0-9._-]/g, '-');
  const localPath = `$HOME/video/${folder}/${file}`;
  return { json: { ...$('Prepare Rows').item.json, ...r, safe_file: file, safe_folder: folder, local_path: localPath } };
});

return items.map(item => {
  const base = $('Prepare Local Download Command').item.json;
  return { json: {
    row_id: base.row_id,
    status: 'done',
    video_url: base.video_url,
    local_path: base.local_path,
    prompt: base.prompt,
    subfolder: base.safe_folder,
    filename_prefix: base.filename_prefix
  }};
});
